INSERT INTO public.designation_statements (occupation_serial, occupation_title, occupation_description, statement_serial, statement) VALUES
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 1, 'אני מלווה אנשים בבניית חוויות מוזיקליות שמעצימות רגשות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 2, 'אני יוצר סביבה שבה מוזיקה מחברת בין אנשים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 3, 'אני מלווה אמנים בהפקת יצירות שמגיעות ללב הקהל.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 4, 'אני מעורר השראה ומוטיבציה דרך מוזיקה איכותית.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 5, 'אני מסייע למוזיקאים לבטא את עצמם באופן יצירתי.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 6, 'אני יוצר חוויות שמאפשרות למשתתפים להרגיש חלק מהמוזיקה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 7, 'אני מלווה תהליכי הפקה מוזיקלית משלב הרעיון ועד הביצוע.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 8, 'אני מסייע ביצירת סאונד מקצועי שמעצים את המסר האמנותי.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 9, 'אני מלווה אמנים לפתח סגנון מוזיקלי ייחודי ואותנטי.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 10, 'אני יוצר מופעים שמחברים בין קהל למוזיקה בצורה חווייתית.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 11, 'אני מלווה תהליכים חינוכיים דרך מוזיקה והפקה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 12, 'אני מעורר השראה למוזיקאים צעירים לגלות את הקול הפנימי שלהם.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 13, 'אני יוצר חוויות שמעוררות זיכרונות ורגשות בקרב הקהל.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 14, 'אני מלווה תהליכים שמפתחים מיומנויות טכניות ומוזיקליות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 15, 'אני מסייע בהעברת מסרים חברתיים או חינוכיים דרך מוזיקה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 16, 'אני יוצר מוזיקה שמחברת בין תרבויות וקהילות שונות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 17, 'אני מלווה אמנים בתהליכי כתיבה והלחנה מקוריים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 18, 'אני מסייע ביצירת סאונד מותאם למופעים חיים או להקלטות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 19, 'אני מלווה תהליכי הפקה שמעצימים ביטחון עצמי והבעה אישית.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 20, 'אני יוצר סדנאות מוזיקה שמפתחות יצירתיות ותקשורת.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 21, 'אני מלווה הקלטות שמבטיחות איכות סאונד גבוהה ומקצועית.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 22, 'אני מסייע להפיק חוויות מוזיקליות שמחזקות את הקשר בין משתתפים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 23, 'אני יוצר מוזיקה שמסייעת בהעצמת תחושת קהילה ושייכות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 24, 'אני מלווה תהליכים שמחברים בין כישורים טכניים ליצירתיות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 25, 'אני מסייע לאמנים למצוא את הקול המיוחד שלהם.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 26, 'אני יוצר הפקות שמחברות בין טכנולוגיה למוזיקה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 27, 'אני מלווה תהליכי יצירה שמפתחים כישורים מוזיקליים מגוונים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 28, 'אני מסייע ביצירת סאונד שמעצים חוויות רגשיות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 29, 'אני יוצר מופעים שמחדשים ומפתיעים את הקהל.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 30, 'אני מלווה אמנים לפתח זהות מוזיקלית ייחודית.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 31, 'אני מסייע בהפקת אלבומים ומופעים ברמה מקצועית גבוהה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 32, 'אני יוצר חוויות מוזיקליות שמעצימות את היצירתיות האישית.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 33, 'אני מלווה תהליכים של הפקה מוזיקלית משולבת עם חינוך.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 34, 'אני מסייע להפיק סאונד שמשדר מקצועיות ואותנטיות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 35, 'אני יוצר סדנאות שמפתחות מיומנויות הקשבה וביטוי מוזיקלי.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 36, 'אני מלווה אמנים בהפקת יצירות מקוריות ומרגשות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 37, 'אני מסייע בקידום מוזיקה שמחברת בין קהל לאמן.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 38, 'אני יוצר מוזיקה שמחזקת את תחושת השייכות והקהילתיות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 39, 'אני מלווה תהליכים שמפתחים כישורי יצירה והפקה אישיים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 40, 'אני מסייע בהנגשת מוזיקה חווייתית לכל סוגי הקהלים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 41, 'אני יוצר חוויות שמעוררות השראה ורגש בקרב הקהל.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 42, 'אני מלווה אמנים בתהליך הפקת סינגלים ואלבומים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 43, 'אני מסייע בהקלטות והפקת מוזיקה ברמה מקצועית גבוהה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 44, 'אני יוצר סדנאות מוזיקה שמפתחות ביטחון עצמי וכישורי ביטוי.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 45, 'אני מלווה מופעים שמחברים בין אמנות לטכנולוגיה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 46, 'אני מסייע לאמנים להפיק תוכן מוזיקלי שמחובר לערכים אישיים.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 47, 'אני יוצר מוזיקה שמעצימה חוויות רגשיות וחברתיות.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 48, 'אני מלווה תהליכים שמפתחים כישורי סאונד והפקה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 49, 'אני מסייע ביצירת מופעים שמעניקים הנאה והשראה.'),
  (46, 'מוסיקה והפקה מוזיקלית', 'נגנים, מפיקים, טכנאי סאונד', 50, 'אני יוצר חוויות מוזיקליות שמחזקות את הקשר בין אנשים ואמנות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 1, 'אני מלווה אנשים ביצירת סביבות טכנולוגיות בטוחות ויעילות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 2, 'אני מסייע לארגונים לנהל מערכות מחשוב מתקדמות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 3, 'אני יוצר פתרונות טכנולוגיים שמייעלים תהליכים ארגוניים.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 4, 'אני מלווה צוותים בפיתוח תשתיות תקשורת אמינות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 5, 'אני מסייע למשתמשים להבין ולנצל את הטכנולוגיה בצורה מיטבית.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 6, 'אני מלווה תהליכי אבטחת מידע שמגנים על נתונים קריטיים.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 7, 'אני מסייע בחיבור בין אנשים לטכנולוגיה בצורה נגישה ופשוטה.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 8, 'אני יוצר מערכות IT שמאפשרות עבודה יעילה ושיתוף מידע.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 9, 'אני מלווה פתרונות תמיכה טכנית שמספקים מענה מהיר ואמין.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 10, 'אני מסייע לארגונים לפתח תשתיות מחשוב מתקדמות וגמישות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 11, 'אני יוצר מערכות שמפשטות תהליכים מורכבים ומייעלות עבודה.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 12, 'אני מלווה צוותים ביישום פתרונות תוכנה מתקדמים.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 13, 'אני מסייע לארגונים לשמור על רציפות פעילות טכנולוגית.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 14, 'אני מלווה תהליכי ניהול רשתות שמבטיחים חיבור יציב ובטוח.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 15, 'אני מסייע בהטמעת כלים דיגיטליים שמעלים פרודוקטיביות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 16, 'אני יוצר חוויות משתמש טכנולוגיות שמקלות על עבודה ותקשורת.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 17, 'אני מלווה צוותים בבחירת פתרונות IT מותאמים לארגון.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 18, 'אני מסייע בהגנה על מערכות מחשוב מפני איומים מתקדמים.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 19, 'אני יוצר פתרונות טכנולוגיים שמעצימים עבודת צוות ושיתוף ידע.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 20, 'אני מלווה תהליכים של תחזוקה ושדרוג מערכות מחשוב.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 21, 'אני מסייע לארגונים למנף טכנולוגיה להשגת מטרות עסקיות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 22, 'אני יוצר פתרונות IT שמחזקים יעילות ותפעול שוטף.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 23, 'אני מלווה משתמשים בהטמעת מערכות חדשות בצורה חלקה.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 24, 'אני מסייע בארגון מידע בצורה נוחה ואינטואיטיבית.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 25, 'אני יוצר תשתיות מחשוב שמספקות אמינות וביצועים גבוהים.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 26, 'אני מלווה צוותים בבניית רשתות תקשורת יציבות ובטוחות.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 27, 'אני מסייע בארגון תהליכי תמיכה טכנית מהירים ומקצועיים.'),
  (47, 'מחשוב ו-IT', 'תשתיות תקשורת, ניהול רשתות, תמיכה טכנית', 28, 'אני יוצר פתרונות שמותאמים לצרכים משתנים של הארגון.'),
