  (48, 'תחום ההדפסה והפרסום', 'בתי דפוס, עיצוב מודעות, קופירייטינג', 50, 'אני מסייע ביצירת חוויית מותג שלמה, שמשלבת תוכן, ויזואליה ואסטרטגיה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 1, 'אני מלווה צוותי חינוך ביצירת סביבה לימודית איכותית ומעצימה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 2, 'אני מסייע למנהלים לפתח אסטרטגיות חינוכיות שמקדמות הצלחה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 3, 'אני יוצר תוכניות לימוד שמחזקות את היכולות האישיות של התלמידים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 4, 'אני מלווה בתהליכי פיקוח על בתי ספר לשיפור איכות ההוראה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 5, 'אני מסייע בהטמעת חדשנות ופדגוגיה מתקדמת במוסדות החינוך.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 6, 'אני מלווה צוותי מורים בהכשרות מקצועיות שמגבירות את האפקטיביות.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 7, 'אני מסייע בהקניית כלים לניהול זמן ומשאבים במוסדות החינוך.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 8, 'אני יוצר מערכות ניהול מידע שמייעלות את עבודת הצוות החינוכי.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 9, 'אני מלווה בתי ספר בתהליכי הערכה והסמכה מקצועית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 10, 'אני מסייע בשיפור חוויית התלמידים והצוות באמצעות ניהול איכותי.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 11, 'אני יוצר תהליכים שמקדמים מעורבות והשתתפות פעילה של תלמידים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 12, 'אני מלווה מנהלים בפיתוח תרבות ארגונית חיובית בבית הספר.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 13, 'אני מסייע בהטמעת תוכניות חינוכיות מותאמות לצרכים משתנים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 14, 'אני מלווה בתכנון והוצאה לפועל של פרויקטים חינוכיים חדשניים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 15, 'אני מסייע בהובלת צוותי הוראה להשגת מטרות חינוכיות ברורות.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 16, 'אני יוצר סביבות לימוד שמקדמות מצוינות ושיתוף פעולה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 17, 'אני מלווה במעקב אחרי הישגים והתקדמות התלמידים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 18, 'אני מסייע בהטמעת מערכות משוב והערכה מתקדמות.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 19, 'אני יוצר כלים לפיתוח מקצועי של צוותי חינוך.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 20, 'אני מלווה בתהליכי ייעוץ אסטרטגי למנהלי מוסדות חינוך.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 21, 'אני מסייע בתכנון תכניות שנתיות שמותאמות לצרכים פדגוגיים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 22, 'אני יוצר תהליכים שמגבירים מוטיבציה ושייכות בקרב תלמידים וצוות.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 23, 'אני מלווה בתי ספר בהטמעת כלים דיגיטליים להוראה וללמידה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 24, 'אני מסייע בפיתוח מדדים להערכת הצלחה חינוכית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 25, 'אני יוצר פתרונות לניהול משברים ושיפור סביבת הלמידה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 26, 'אני מלווה צוותים בהכנת תוכניות לימוד מגוונות ומאתגרות.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 27, 'אני מסייע ביצירת שיתופי פעולה בין מוסדות חינוך וקהילה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 28, 'אני יוצר כלים לניהול משימות, פרויקטים ותהליכים חינוכיים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 29, 'אני מלווה בתי ספר בתהליכי ייעוץ ושיפור איכות ההוראה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 30, 'אני מסייע בפיתוח מערכות חינוך מותאמות לדרישות המשתנות של השוק.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 31, 'אני יוצר תכניות הכשרה והעצמה למורים ולמנהלים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 32, 'אני מלווה בהטמעת פתרונות חדשניים להעצמת תלמידים עם צרכים מיוחדים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 33, 'אני מסייע בתכנון אסטרטגיות לחיזוק הצלחה אקדמית ובין-אישית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 34, 'אני יוצר סביבות למידה שמקדמות יצירתיות וחשיבה ביקורתית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 35, 'אני מלווה מנהלים בקבלת החלטות מבוססות נתונים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 36, 'אני מסייע בפיתוח תכניות להנעת צוותי הוראה למיצוי יכולותיהם.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 37, 'אני יוצר מערכות למידה שמספקות תמיכה לכלל התלמידים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 38, 'אני מלווה בתי ספר בתהליכי ניהול תקציב ותכנון משאבים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 39, 'אני מסייע בהובלת צוותים למיצוי הפוטנציאל החינוכי של כל תלמיד.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 40, 'אני יוצר פתרונות לניהול זמן וארגון יעיל במוסדות חינוך.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 41, 'אני מלווה מנהלים ביצירת חזון חינוכי ברור ומחובר לערכים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 42, 'אני מסייע בהטמעת תהליכי הערכה מתמשכת ומשוב בונה.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 43, 'אני יוצר כלים לשיפור תקשורת ושיתוף פעולה בין צוותים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 44, 'אני מלווה בתי ספר בתהליכי קידום מצוינות חינוכית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 45, 'אני מסייע בפיתוח תכניות למנהיגות חינוכית בקרב צוותים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 46, 'אני יוצר תהליכים שמגבירים מעורבות הורים ותמיכה קהילתית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 47, 'אני מלווה בתכנון והטמעת תוכניות למידה מותאמות אישית.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 48, 'אני מסייע בשיפור סביבת העבודה והלמידה למורים ותלמידים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 49, 'אני יוצר פתרונות לניהול יעיל של צוותי חינוך מרובי תחומים.'),
  (49, 'ניהול מערכות חינוך', 'מנהלי בתי ספר, מפקחים, אנשי פדגוגיה', 50, 'אני מלווה בתי ספר בתהליכי שיפור מתמיד שמביאים לתוצאות איכותיות.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 1, 'אני מפתח ומייעל תהליכים תעשייתיים לשיפור פריון ואיכות.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 2, 'אני מלווה צוותי מהנדסים בהטמעת פתרונות חדשניים במפעלים.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 3, 'אני מסייע בתכנון, תחזוקה ושדרוג של מערכות מכניות מורכבות.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 4, 'אני יוצר פתרונות למיכון מתקדם שמפחיתים תקלות ועלויות.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 5, 'אני מלווה בתהליכי ייעול קווי ייצור ותפעול תעשייתי.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 6, 'אני מסייע בהטמעת אוטומציה ורובוטיקה במפעלים ובמפעלי תעשייה.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 7, 'אני יוצר כלים לניהול פרויקטים הנדסיים מורכבים.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 8, 'אני מלווה בהטמעת תוכניות בטיחות ותקינה בתעשייה.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 9, 'אני מסייע בהדרכת צוותים טכניים לשיפור מיומנויות עבודה.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 10, 'אני יוצר פתרונות הנדסיים לבעיות מורכבות בתפעול תעשייתי.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 11, 'אני מלווה בתכנון ותחזוקה של מכונות ציוד כבד.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 12, 'אני מסייע בשיפור איכות המוצרים והפחתת פסולת בתעשייה.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 13, 'אני יוצר תוכניות הדרכה למפעילי מכונות ומטפלים בתקלות.'),
  (50, 'מיכון ותעשייה כבדה', 'מהנדסי מכונות, טכנאים תעשייתיים', 14, 'אני מלווה פרויקטים להטמעת מערכות חכמות במפעלים.'),
